INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('d48aeb0f31248eab', 'WA', '["federal","state","county"]', 'ballot_access', 'What is the Top-2 primary system in Washington?', '["How does the Washington blanket primary work?","Do candidates run by party in the WA primary?","Can two Democrats run against each other in the general election?"]', 'Washington uses a nonpartisan Top-2 primary system. Under RCW 29A.52.112, all candidates for an office appear on a single primary ballot, regardless of party preference. All registered voters can vote for any candidate. The two candidates who receive the most votes advance to the general election, meaning two candidates of the same party (e.g., two Democrats or two Republicans) frequently face each other in November.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=29A.52.112', 'RCW 29A.52.112', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('6081abf7962b3ce6', 'WA', '["federal","state","county"]', 'ballot_access', 'Is Washington''s Top-2 primary system legally established and upheld?', '["When did Washington adopt the jungle primary?","Initiative 872 history","Supreme Court ruling on Washington primary system"]', 'Yes. The Top-2 primary was established by citizen Initiative 872 in 2004. After legal challenges by political parties, the United States Supreme Court formally upheld the constitutionality of the system in the 2008 decision Washington State Grange v. Washington State Republican Party, allowing it to become fully operative.', 'https://www.sos.wa.gov/elections/voters/top-2-primary-answers-frequently-asked-questions', 'Washington Secretary of State - Top 2 Primary FAQ', '2026-04-21', 'static', 'official_source_direct', 'Campaign strategists and candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('320e37df0df0422b', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'Do voters register by political party in Washington?', '["Washington party registration rules","How do I target registered Democrats in Washington?","Closed primary voting in WA"]', 'No. Washington does not have party registration. Voters do not indicate any political party affiliation when they register to vote. Operationally, campaigns cannot pull a voter file of ''registered Democrats'' or ''registered Republicans'' and must instead rely on past voting history, primary participation, and modeling to identify target voters.', 'https://www.sos.wa.gov/elections/voters/voter-registration', 'Washington Secretary of State - Voter Registration', '2026-04-21', 'static', 'official_source_direct', 'Campaign strategists and GOTV teams', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('045f59d58fee1e46', 'WA', '["federal","state","county"]', 'ballot_access', 'Does a candidate''s party preference mean they are nominated by that party?', '["Party nomination vs party preference in Washington","How do political parties nominate candidates in WA?","Does the party endorse candidates on the ballot?"]', 'No. In Washington''s Top-2 system, a candidate self-declares their ''party preference'' when filing for office, which is printed on the ballot (e.g., ''Prefers Democratic Party''). This is strictly for the information of voters and does not imply that the candidate is nominated, endorsed, or approved by that political party. Parties may endorse candidates privately, but they do not nominate them for the general election ballot.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=29A.52.112', 'RCW 29A.52.112(4)', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('33ef4fc7bf7b93e1', 'WA', '["state"]', 'election_dates', 'Which statewide executive offices are on the ballot in Washington in 2026?', '["Washington AG race 2026","Are there any statewide constitutional officers up for election in 2026?","Washington Secretary of State election 2026"]', 'There are no regularly scheduled statewide executive elections in Washington in 2026. Washington elects all of its statewide executive officers (Governor, Lt. Governor, Secretary of State, Attorney General, Treasurer, Auditor, Insurance Commissioner, Commissioner of Public Lands, and Superintendent of Public Instruction) concurrently for four-year terms during Presidential election years (e.g., 2024, 2028).', 'https://www.sos.wa.gov/elections/candidates', 'Washington Secretary of State - Elections', '2026-04-21', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('0203d33733e927fa', 'WA', '["federal","state"]', 'election_dates', 'Is there a race for Washington Governor or U.S. Senate in 2026?', '["Bob Ferguson 2026 re-election","Are Patty Murray or Maria Cantwell on the 2026 ballot?","Washington top of ticket 2026"]', 'No. Governor Bob Ferguson (D) was elected in 2024 and his term runs until 2028. U.S. Senator Patty Murray (D) was re-elected in 2022 (next up in 2028), and U.S. Senator Maria Cantwell (D) was re-elected in 2024 (next up in 2030). The 2026 ballot is strictly a midterm cycle focused on the U.S. House, state legislature, and local offices.', 'https://www.sos.wa.gov/elections/candidates', 'Washington Secretary of State', '2026-04-21', 'per_cycle', 'official_source_direct', 'Federal and Statewide candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('56d14bed1ba42cac', 'WA', '["state"]', 'election_dates', 'What is the 2026 election cycle for the Washington State Legislature?', '["Are all Washington House seats up in 2026?","Washington Senate election cycle 2026","Which legislative districts are on the ballot in WA?"]', 'All 98 seats in the Washington House of Representatives are up for election in 2026, as members serve two-year terms. The Washington State Senate has 49 members who serve staggered four-year terms; 24 of the 49 Senate districts are on the 2026 ballot. Unlike some states, this is a specific mix of both odd- and even-numbered districts.', 'https://leg.wa.gov/Senate/Senators/Pages/default.aspx', 'Washington State Legislature', '2026-05-14', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('458e6689fdf0fc73', 'WA', '["federal"]', 'election_dates', 'How many U.S. House districts are in Washington for the 2026 election?', '["Washington congressional apportionment","Are all WA congressional seats up in 2026?","Number of US Representatives from Washington"]', 'Washington is apportioned 10 U.S. House districts. All 10 seats will be on the 2026 ballot, as Representatives serve two-year terms.', 'https://www.sos.wa.gov/elections/candidates', 'Washington Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('4b790b609c342fe7', 'WA', '["federal","state","county"]', 'election_dates', 'When is the Washington primary election in 2026?', '["Washington primary date 2026","When do WA voters cast primary ballots?","August 2026 primary Washington"]', 'The Washington primary election will be held on Tuesday, August 4, 2026. By statute (RCW 29A.04.311), the primary is held on the first Tuesday in August of even-numbered years.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=29A.04.311', 'RCW 29A.04.311', '2026-04-21', 'per_cycle', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('75d441a1a2725091', 'WA', '["federal","state","county"]', 'election_dates', 'When is the 2026 general election in Washington?', '["Washington general election date 2026","November election date WA","When is Election Day 2026 in Washington?"]', 'The 2026 general election in Washington will be held on Tuesday, November 3, 2026.', 'https://www.sos.wa.gov/elections', 'Washington Secretary of State', '2026-04-21', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('b281cefbb265a94c', 'WA', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for Washington in 2026?', '["When do candidates file for office in Washington?","Washington filing week dates 2026","May filing deadline WA"]', 'Washington uses a ''filing week'' rather than a single deadline. For the 2026 cycle, candidate filing week takes place from Monday, May 4, 2026, through Friday, May 8, 2026. Declarations of candidacy must be submitted electronically or in person to the appropriate filing officer during this specific window per RCW 29A.24.050.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=29A.24.050', 'RCW 29A.24.050', '2026-04-21', 'per_cycle', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('f7866bc248a6ba36', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Washington a universal mail ballot state?', '["Do all voters get a mail ballot in Washington?","Washington vote-by-mail system","Are there traditional polling places in WA?"]', 'Yes. Washington is a universal vote-by-mail state. Under RCW 29A.40.010, every active registered voter is automatically mailed a ballot roughly 18 days before each election. There are no traditional in-person voting precincts, though counties provide voting centers for accessibility devices, same-day registration, and ballot replacement.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=29A.40.010', 'RCW 29A.40.010', '2026-04-21', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('f23eb87fa879454a', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Washington allow same-day voter registration?', '["Can I register on Election Day in Washington?","WA voter registration deadlines","Registering at a voting center WA"]', 'Yes. Washington allows same-day voter registration. While online and mail-in registrations must be received 8 days before the election, voters may register or update their address in person at a county elections office or voting center until 8:00 p.m. on Election Day per RCW 29A.08.140.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=29A.08.140', 'RCW 29A.08.140', '2026-04-21', 'static', 'statute_citation', 'Voters and GOTV teams', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('79d851b6d8d29824', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return a mail ballot in Washington?', '["Washington ballot postmark rule","When is my WA ballot due?","Does Washington have a postmark grace period?"]', 'Ballots must either be deposited in an official county drop box by 8:00 p.m. on Election Day, OR postmarked by the USPS no later than Election Day. Because Washington requires a valid Election Day postmark (and not just physical receipt by 8pm), ballots arriving in the mail days after the election are counted as long as the postmark is valid.', 'https://www.sos.wa.gov/elections/voters/voting-mail', 'Washington Secretary of State - Voting by Mail', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('3dec746261ea9f43', 'WA', '["state"]', 'candidate_eligibility', 'Does Washington have term limits for the state legislature?', '["How long can a Washington State Senator serve?","Legislative term limits WA","Are there term limits for the WA House of Representatives?"]', 'No. Washington does not have term limits for its state legislature. In 1998, the Washington Supreme Court struck down a statutory term limits measure passed by voters, ruling that term limits for state constitutional offices would require a constitutional amendment. None currently exists.', 'https://ballotpedia.org/Washington_State_Legislature', 'Washington State Legislature - Term Limits', '2026-04-21', 'static', 'secondary_source', 'State legislative candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('9b3c45562880c083', 'WA', '["federal","state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance laws in Washington?', '["Where do I file campaign finance reports in WA?","What is the Washington PDC?","Does the WA Secretary of State handle campaign finance?"]', 'Campaign finance and disclosure laws in Washington are administered by the Public Disclosure Commission (PDC), an independent state agency. This differs from many states where campaign finance is handled directly by the Secretary of State. All state and local candidates must register and file their contribution and expenditure reports through the PDC''s electronic system.', 'https://www.pdc.wa.gov/', 'Washington Public Disclosure Commission', '2026-04-21', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('3371560697c20a4e', 'WA', '["state","county"]', 'finance_ethics', 'How do campaign contribution limits work in Washington?', '["Does Washington cap individual donations?","Washington PDC contribution limits framework","Are there limits for state legislative races in WA?"]', 'Washington imposes strict contribution limits on individuals, PACs, and corporations giving to state executive, legislative, and some county candidates. The Public Disclosure Commission (PDC) adjusts these limits periodically for inflation. Limits are applied per election, meaning a donor may give the maximum amount for the primary and again for the general election.', 'https://www.pdc.wa.gov/rules-enforcement/guidelines-manuals/contribution-limits', 'Washington PDC - Contribution Limits', '2026-04-21', 'per_cycle', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('29b392fac8db2144', 'WA', '["federal","state"]', 'redistricting', 'How are district maps drawn in Washington?', '["Washington State Redistricting Commission structure","Does the WA legislature draw the maps?","Who draws congressional boundaries in Washington?"]', 'District maps are drawn by the Washington State Redistricting Commission, a bipartisan five-member body established every ten years. The majority and minority leaders of the state House and Senate each appoint one voting commissioner. Those four commissioners then appoint a non-voting, nonpartisan fifth member to serve as the chairperson.', 'https://www.redistricting.wa.gov/commissioners.html', 'Washington State Redistricting Commission', '2026-04-21', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('79e919dbaff590c4', 'WA', '["state","county","municipal"]', 'recall_rules', 'What are the legal grounds and signature thresholds to recall an elected official in Washington?', '["Can I recall a state senator in Washington without cause?","Washington recall process and rules","Misfeasance and malfeasance recall WA"]', 'Unlike states with no-grounds recall, Washington requires specific legal grounds: misfeasance, malfeasance, or a violation of the oath of office (Article I, Section 33, WA Constitution). A superior court must determine the charges are factually and legally sufficient before petitioning begins. Proponents must then gather valid signatures equal to 25% of the total votes cast for that office in the preceding election (35% for certain local offices).', 'https://app.leg.wa.gov/rcw/default.aspx?cite=29A.56.110', 'RCW 29A.56.110', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('b8bf0005b5f9de5a', 'WA', '["state"]', 'ballot_access', 'What is the difference between an Initiative to the People and an Initiative to the Legislature in Washington?', '["Types of ballot initiatives in Washington","How to propose a law in WA","Initiative process tracks Washington"]', 'An ''Initiative to the People'' goes directly onto the ballot for voters to decide, with signatures typically due in July. An ''Initiative to the Legislature'' is submitted to the state legislature first (signatures due in late December); if the legislature rejects, ignores, or amends the proposal, the original measure is then placed on the statewide ballot. Both require signatures from registered voters equal to 8% of the votes cast in the last gubernatorial election.', 'https://www.sos.wa.gov/elections/initiatives', 'Washington Secretary of State - Initiatives', '2026-04-21', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('06ba0b3ba5277b8e', 'WA', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor or statewide executive office in Washington?', '["How old do you have to be to be Governor of WA?","Washington Governor residency requirements","Qualifications for statewide office Washington"]', 'Under Article III, Section 25 of the Washington Constitution, the requirements are very minimal: ''No person, except a citizen of the United States and a qualified elector of this state, shall be eligible to hold any state office.'' A qualified elector is a registered voter who is at least 18 years old. There are no extended 30-year age minimums or 7-year residency requirements as seen in other states.', 'https://leg.wa.gov/CodeReviser/Pages/WAConstitution.aspx', 'Washington Constitution, Article III, Section 25', '2026-04-21', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('fc50a692f3f09073', 'WA', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for the Washington State Legislature?', '["Qualifications for WA State Representative","Residency requirement Washington State Senate","Do I have to live in my district to run in WA?"]', 'Under Article II, Section 7 of the Washington Constitution, a candidate for the state legislature must be a citizen of the United States and a ''qualified voter in the district for which he is chosen.'' This means the candidate must be a registered voter living within the boundaries of the specific legislative district they seek to represent.', 'https://leg.wa.gov/CodeReviser/Pages/WAConstitution.aspx', 'Washington Constitution, Article II, Section 7', '2026-04-21', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('1851b317d06f2a41', 'WA', '["federal","state","county"]', 'ballot_access', 'How can a write-in candidate advance from the primary to the general election in Washington?', '["Washington Top-2 write-in rules","Do write-in candidates move on to November in WA?","RCW 29A.24.311 write-in threshold"]', 'To advance to the general election under the Top-2 system, a write-in candidate must file a formal declaration of candidacy, finish as one of the top two vote-getters in the primary, AND receive a number of votes equal to at least 1% of the total votes cast for that specific position (or equal to the number of signatures required for a filing fee petition), per RCW 29A.24.311.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=29A.24.311', 'RCW 29A.24.311', '2026-04-21', 'static', 'statute_citation', 'Write-in candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('8ba7f8b29521f144', 'WA', '["state"]', 'ballot_access', 'How is a vacancy in the Washington State Legislature filled?', '["Who appoints a replacement State Senator in WA?","Legislative vacancy committee Washington","Special election for WA House vacancy"]', 'Under Article II, Section 15 of the Washington Constitution, if a legislative vacancy occurs, the state political party central committee of the vacating member''s party submits a list of three nominees. The county legislative authority (e.g., county council or commissioners) then formally appoints one of those three nominees to fill the seat until the next general election.', 'https://leg.wa.gov/CodeReviser/Pages/WAConstitution.aspx', 'Washington Constitution, Article II, Section 15', '2026-04-21', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('8fbba525128a2f91', 'WA', '["federal"]', 'ballot_access', 'How is a vacancy in a Washington U.S. Senate seat filled?', '["Governor appointment US Senate Washington","Special election for US Senate WA","Washington rule for replacing a US Senator"]', 'Under RCW 29A.28.030, if a vacancy occurs in the U.S. Senate from Washington, the Governor immediately makes a temporary appointment to fill the seat. The appointed Senator serves until the people fill the vacancy via a special election, which is generally held at the next state general election.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=29A.28.030', 'RCW 29A.28.030', '2026-04-21', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('228ac267106ddbbf', 'WA', '["state","county"]', 'finance_ethics', 'What are the individual contribution limits for Washington state candidates in 2026?', '["How much can an individual donate to a Washington Governor candidate?","Current campaign contribution limits for state legislature in WA","PDC individual donation caps 2026 election"]', 'For the 2026 cycle, individual contribution limits are $2,400 per election for statewide executive candidates (Governor, Attorney General, etc.) and $1,200 per election for state legislative candidates (Senate and House). Primary and general elections are considered separate, meaning a donor can give the maximum for the primary and again for the general. Limits are periodically adjusted for inflation by the Public Disclosure Commission (PDC).', 'https://www.pdc.wa.gov/rules-enforcement/guidelines-restrictions/contribution-limits', 'Washington PDC - Contribution Limits', '2026-04-21', 'per_cycle', 'official_source_direct', 'State candidates and Donors', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('ad5fccbbd4e925eb', 'WA', '["state","county"]', 'finance_ethics', 'Are corporations allowed to contribute directly to candidate campaigns in Washington?', '["Corporate contribution ban Washington state","Can a business donate to my campaign in WA?","Corporate campaign finance rules Washington"]', 'Yes. Unlike the federal government and some states, Washington allows direct corporate contributions to state and local candidate campaigns. Corporations are subject to the exact same contribution limits as individuals ($2,400 per election for statewide offices, $1,200 for legislative offices). Note that some local jurisdictions, like Seattle, ban contributions from foreign-influenced corporations.', 'https://www.pdc.wa.gov/rules-enforcement/guidelines-restrictions/contribution-limits', 'Washington PDC - Contribution Limits', '2026-04-21', 'static', 'official_source_direct', 'Candidates and Businesses', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('97d6408d3ee1416c', 'WA', '["state","county","municipal"]', 'finance_ethics', 'What is the mandatory electronic filing system used by the Washington PDC?', '["Washington PDC electronic filing portal","ORCA system Washington campaign finance","How to file campaign reports in WA"]', 'The Public Disclosure Commission uses a mandatory web-based campaign finance management system called ORCA (Online Reporting of Campaign Activity). All state and local candidates who meet the threshold to file full reports must use ORCA or approved third-party vendor software to electronically submit their C-3 (contributions) and C-4 (expenditures) reports.', 'https://www.pdc.wa.gov/registration-reporting/candidates-committees/electronic-reporting-tools/online-reporting-campaign-activity-orca', 'Washington PDC - ORCA System', '2026-04-21', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('b3e2e22bc0056310', 'WA', '["state","county","municipal"]', 'finance_ethics', 'What is the 2026 campaign finance reporting schedule for Washington state candidates?', '["WA campaign finance filing dates 2026","When are PDC C-4 reports due for Washington 2026 primary?","Washington pre-primary and pre-general report deadlines"]', 'Candidates must file C-4 summary reports 21 days and 7 days before both the primary and general elections. Post-election reports are due on the 10th of the month following the election (e.g., September 10th for the August primary, December 10th for the November general). In months without an election-specific report, campaigns that exceed $750 in activity must file a C-4 by the 10th of the following month.', 'https://www.pdc.wa.gov/registration-reporting/candidates-committees/registration-reporting-basics', 'Washington PDC - Reporting Basics', '2026-04-21', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('556e041db9ff2ef6', 'WA', '["state","county","municipal"]', 'finance_ethics', 'What is Washington''s Last-Minute Contribution (LMC) reporting threshold?', '["WA 48-hour large contribution report threshold","PDC rapid disclosure rules near elections","When do I file a 24-hour report in Washington?"]', 'During the 7 days before a primary and 21 days before a general election, candidates must file a special Last-Minute Contribution (LMC) report for any contribution (or aggregate from one source) of $1,500 or more. The candidate must file the report within 48 hours of receiving the contribution. Political committees making the contribution must report it within 24 hours.', 'https://www.pdc.wa.gov/registration-reporting/candidates-committees/contributions/special-limits-and-reports-last-minute-contributions', 'Washington PDC - Last-Minute Contributions', '2026-04-21', 'static', 'official_source_direct', 'All candidates and committees', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('cbb66d50bbdc7aac', 'WA', '["state"]', 'finance_ethics', 'Does Washington state provide public financing or matching funds for state campaigns?', '["Public matching funds for Washington candidates","State funded campaigns Washington status","Clean elections program Washington state"]', 'No. Washington state does not have a public financing or matching funds program for state-level candidates (Governor, Legislature, etc.). Campaigns are funded entirely through private contributions. However, at the municipal level, the City of Seattle operates a ''Democracy Voucher'' public financing program for local city races.', 'https://www.pdc.wa.gov/', 'Washington Public Disclosure Commission', '2026-04-21', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('6379a092005ba2cc', 'WA', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in Washington?', '["WA personal use prohibition campaign finance","Can I use campaign money for personal expenses in Washington?","Prohibited expenditures Washington PDC"]', 'Yes. Under RCW 42.17A and PDC rules, it is strictly prohibited to use campaign funds for personal expenses. Expenditures must be directly related to the campaign. Prohibited uses include personal living expenses, gym memberships, and non-campaign travel. Lost earnings due to campaigning may be reimbursed only if strictly documented, and candidates can be reimbursed for childcare that exists solely because of campaign activities.', 'https://www.pdc.wa.gov/rules-enforcement/guidelines-restrictions/allowable-uses-campaign-funds', 'Washington PDC - Allowable Uses of Campaign Funds', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('40e2f788950f48e6', 'WA', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Washington?', '["Washington in-kind contribution valuation rules","Reporting non-monetary donations Washington campaign","Fair market value for in-kind gifts WA"]', 'In-kind contributions (donated goods or services) must be valued at fair market value—the amount it would cost to purchase the item or service on the open market. They count toward the donor''s contribution limit just like cash and must be reported on Schedule B of the C-4 expenditure report.', 'https://www.pdc.wa.gov/registration-reporting/candidates-committees/contributions', 'Washington PDC - Contributions', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('ee414906eae81e19', 'WA', '["state","county","municipal"]', 'finance_ethics', 'What are the rules for a candidate loaning personal funds to their own campaign in Washington?', '["Washington candidate personal loan limits","Can I pay myself back for a campaign loan in WA?","Reporting candidate loans in ORCA"]', 'A candidate may contribute unlimited personal funds to their own campaign. However, if the candidate structures the funding as a loan and wishes to be repaid by the campaign committee, repayment is statutorily limited. A campaign may not repay loans to the candidate in excess of $7,500 per election.', 'https://www.pdc.wa.gov/registration-reporting/candidates-committees/contributions/contributions-candidate', 'Washington PDC - Contributions by the Candidate', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('94fded78eb0c8c37', 'WA', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer is required on Washington campaign advertisements and mailers?', '["Washington ''Paid for by'' requirements","Campaign ad disclaimer rules WA","Sponsor identification Washington political ads"]', 'Under WAC 390-18, most political advertising must include a ''Sponsor Identification'' (disclaimer) stating ''Paid for by [Committee Name]'' along with the campaign''s address. For independent expenditure ads not sponsored by a candidate, the disclaimer must also explicitly list the committee''s top five contributors if they gave over $700 in the past year.', 'https://www.pdc.wa.gov/rules-enforcement/guidelines-restrictions/political-advertising-guide', 'Washington PDC - Political Advertising Guide', '2026-04-21', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('4a6f75c4ada340eb', 'WA', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Washington?', '["WA campaign coordination rules","When is a PAC expenditure not independent in Washington?","Prohibition on candidate-PAC coordination WA"]', 'An expenditure is coordinated (and thus treated as an in-kind contribution subject to limits) if it is made with the candidate''s authorization, consent, or at their request or suggestion. Using the same consultants, sharing non-public campaign strategy, or a candidate fundraising for the PAC making the expenditure are strong legal indicators of prohibited coordination under PDC rules.', 'https://www.pdc.wa.gov/rules-enforcement', 'Washington PDC - Rules and Enforcement', '2026-04-21', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('6b2633d7c43a5c1b', 'WA', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Washington?', '["WA PDC late fee","Penalty for missing a Washington campaign finance deadline","PDC fine for late filing WA"]', 'The PDC actively enforces filing deadlines. Minor or first-time late filings may result in a formal warning or a brief adjudicative proceeding with civil penalties ranging from $150 to $500. Serious, repeated, or intentional violations can result in formal commission hearings with civil penalties assessed up to $10,000 per violation.', 'https://www.pdc.wa.gov/rules-enforcement', 'Washington PDC - Enforcement', '2026-04-21', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('3d13728a002b846e', 'WA', '["state"]', 'finance_ethics', 'What are the restrictions on contributions from registered lobbyists to Washington state candidates?', '["WA lobbyist donation ban","Can a lobbyist give to a Washington legislator?","Lobbyist contribution session freeze Washington"]', 'Washington imposes a ''session freeze.'' State officials and candidates for state office are prohibited from soliciting or accepting campaign contributions from anyone, including registered lobbyists, during the regular legislative session, or during any special session. Outside of session, lobbyists may contribute subject to standard individual limits.', 'https://www.pdc.wa.gov/registration-reporting/lobbying', 'Washington PDC - Lobbyist Rules', '2026-04-21', 'static', 'official_source_direct', 'State candidates and Lobbyists', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('940d2c596e966b7f', 'WA', '["state","county","municipal"]', 'finance_ethics', 'When and how must a candidate committee be terminated in Washington?', '["Closing a Washington campaign committee","ORCA committee termination requirements","Final campaign finance report Washington"]', 'A candidate committee may be formally terminated only after it has resolved all outstanding debts, disposed of all surplus funds in a legally permitted manner (e.g., returned to donors, given to charity, or transferred to a future campaign), and achieved a zero bank balance. A final C-4 report must be filed checking the ''Final Report'' box to close the committee.', 'https://www.pdc.wa.gov/registration-reporting/candidates-committees/registration-reporting-basics', 'Washington PDC - Registration & Reporting', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('473edb968bdcdd24', 'WA', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Washington?', '["WA independent expenditure reporting C-6","Disclosure for WA independent expenditure groups","Reporting thresholds for outside spending Washington"]', 'Sponsors making independent expenditures of $1,000 or more must file a C-6 report. If an independent expenditure totals $2,000 or more and is made within 21 days of an election, it must be reported within 24 hours of when the ad is presented to the public. All other independent expenditures must be reported within 5 days.', 'https://pdc.wa.gov/registration-reporting/independent-expenditures/what-report/reporting-thresholds-c-6', 'Washington PDC - Reporting Thresholds C-6', '2026-04-21', 'static', 'official_source_direct', 'Independent groups and PACs', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('62dd5bc87ab1cd56', 'WA', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Washington?', '["US Senate residency requirements Washington","Age to run for Congress in Washington","Federal constitutional requirements for WA candidates"]', 'Federal candidates must meet U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected. District residency is not required for the U.S. House.', 'https://www.sos.wa.gov/elections/candidates', 'Washington Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('d2c4167a8e05ff2c', 'WA', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for elected county officers like Sheriff, Commissioner, and Prosecutor in Washington?', '["Qualifications for WA County Sheriff","Can anyone run for County Prosecutor in Washington?","Washington county official requirements"]', 'County candidates must be registered voters in the county. Specific offices have strict professional requirements: a County Prosecutor must be a licensed attorney admitted to the Washington State Bar (RCW 36.27.010). Under recent law (SB 5974), a County Sheriff must have at least five years of law enforcement experience, peace officer certification, and no felony convictions.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=36.27.010', 'RCW 36.27.010 / SB 5974', '2026-04-21', 'static', 'statute_citation', 'County candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('8c31719b6591c3b0', 'WA', '["judicial"]', 'candidate_eligibility', 'Are Superior Court judges elected or appointed in Washington, and what are the qualifications?', '["Washington Superior Court judge eligibility","Do judges run for election in WA?","Qualifications to run for judge in Washington"]', 'Superior Court judges are elected to four-year terms in nonpartisan elections. Under the Washington Constitution and RCW 2.06.050, a candidate for Superior Court must be admitted to the practice of law in the courts of Washington (a member of the State Bar) and a resident of the state.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=2.06.050', 'RCW 2.06.050', '2026-04-21', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('9480852b7f8c5c8c', 'WA', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements to run for a local school board in Washington?', '["Qualifications for WA school director","Who can run for school board in Washington state?","School district residency requirement WA"]', 'To run for the office of school director (school board member), a candidate must be a United States citizen, a resident of Washington, at least 18 years old, and a registered voter residing within the boundaries of the specific school district (and the specific director district, if applicable) they seek to represent.', 'https://wssda.org/about-us/how-we-are-governed/elections/', 'Washington State School Directors'' Association', '2026-04-21', 'static', 'secondary_source', 'School board candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('a2f90bc52849adc3', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the rules regarding ballot drop boxes in Washington?', '["Are drop boxes secure in WA?","Washington drop box collection rules","When do ballot drop boxes close in Washington?"]', 'Washington law requires counties to provide secure ballot drop boxes. There must be at least one drop box per 15,000 registered voters, and at least one in every city, town, and census-designated place. Boxes must be securely locked and bolted, emptied by bipartisan teams of sworn election workers, and locked promptly at 8:00 p.m. on Election Day.', 'https://www.sos.wa.gov/elections/voters/voting-mail', 'Washington Secretary of State - Voting by Mail', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('1da2bfef810f5d85', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process and deadline in Washington?', '["How to fix a rejected signature in WA","Washington ballot cure process deadline","Missing signature on WA mail ballot"]', 'If a ballot envelope is missing a signature or the signature does not match the voter registration record, the county auditor contacts the voter. The voter is given an opportunity to ''cure'' the issue by signing and returning a cure form. The deadline to cure a signature is the day before the election is officially certified (which is typically 21 days after Election Day).', 'https://www.sos.wa.gov/elections/voters/voting-mail', 'Washington Secretary of State - Voting by Mail', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('845044023bcba208', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Washington have automatic voter registration at the DMV?', '["Is registration automatic at the Washington DOL?","WA motor voter automatic registration","Do I have to register to vote if I get a WA driver''s license?"]', 'Yes. Washington uses Automatic Voter Registration (AVR). Eligible citizens interacting with the Department of Licensing (DOL) for an enhanced driver''s license or ID, or other qualifying state agencies, are automatically registered to vote or have their address updated unless they explicitly opt out.', 'https://www.sos.wa.gov/elections/voters/voter-registration', 'Washington Secretary of State - Voter Registration', '2026-04-21', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('c93c67694915785b', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'Can campaigns purchase the voter file from the state in Washington?', '["Washington voter database access","How to get the voter list in WA","Cost of voter registration data Washington"]', 'Yes. The Washington statewide voter registration database is public record. Campaigns and political committees can request the voter file from the Secretary of State free of charge via a public data request. The file includes names, addresses, and voting history (which elections they participated in), but not how they voted or their phone numbers/emails.', 'https://www.sos.wa.gov/elections/data-research/voter-registration-data', 'Washington Secretary of State - Voter Data', '2026-04-21', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('e066b18035e49a55', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Washington?', '["When are military ballots due in Washington?","UOCAVA return deadline WA","Overseas voting rules Washington state"]', 'Ballots are transmitted to UOCAVA voters at least 45 days prior to the election. To be counted, the ballot declaration must be signed and dated no later than Election Day. Because Washington accepts postmarks, the ballot must be received by the county auditor before the county canvassing board certifies the election results (usually 21 days after the election).', 'https://www.sos.wa.gov/elections/voters/military-overseas-voters', 'Washington Secretary of State - Military & Overseas Voters', '2026-04-21', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('9ea060956c5810ea', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Washington restore voting rights to individuals with felony convictions?', '["Can felons vote in Washington state?","Felony voting rights restoration WA","Voting on parole in Washington"]', 'Yes. Following a law enacted in 2022, an individual convicted of a felony in Washington automatically regains the right to vote immediately upon their release from total confinement (prison). People on community supervision, parole, or probation are fully eligible to register and vote.', 'https://www.sos.wa.gov/elections/voters/voter-registration/felony-convictions-voting-rights', 'Washington Secretary of State - Felony Convictions and Voting', '2026-04-21', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-14T20-58-02_washington_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('899bf0e64fdd35b1', 'WA', '["federal","state"]', 'redistricting', 'What criteria must the Washington Redistricting Commission follow when drawing maps?', '["Washington redistricting rules","Gerrymandering ban Washington state","How are WA congressional maps drawn?"]', 'Under RCW 44.05.090, the bipartisan Washington Redistricting Commission must create districts that have equal population, are as compact and contiguous as possible, preserve communities of interest and political subdivisions, and provide fair and competitive elections. The commission is strictly prohibited from drawing maps that purposely favor or discriminate against any political party or group.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=44.05.090', 'RCW 44.05.090', '2026-05-14', 'static', 'statute_citation', 'Federal and State candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('813212e9ccc12bb4', 'WA', '["federal","state"]', 'redistricting', 'Are the current Washington redistricting maps operative for the 2026 cycle?', '["Legal challenges to Washington districts","Soto Palmer v. Hobbs redistricting","Will WA get new maps for 2026?"]', 'Yes. The current congressional and legislative maps were originally adopted by the Commission in 2021. However, following the federal Soto Palmer v. Hobbs (2023) Voting Rights Act lawsuit, a federal court ordered a redrawn legislative map for the Yakima Valley region (specifically altering Legislative District 15 and surrounding districts) to ensure Hispanic voter representation. These court-altered maps are fully operative for 2026.', 'https://www.sos.wa.gov/elections/data-research/election-data-and-maps', 'Washington Secretary of State - Election Maps', '2026-05-14', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('396fc2435fcfad74', 'WA', '["federal","state"]', 'redistricting', 'Can the Washington State Legislature amend the maps drawn by the Redistricting Commission?', '["Legislature override of Washington redistricting","Can WA lawmakers change district boundaries?","Washington redistricting amendment rules"]', 'Yes, but under highly restricted conditions. According to the Washington Constitution (Article II, Section 43), the legislature can only amend the commission''s maps by a two-thirds supermajority vote in both the House and Senate. Furthermore, any legislative amendment cannot alter the population of any given district by more than 2%.', 'https://leg.wa.gov/CodeReviser/Pages/WAConstitution.aspx', 'Washington Constitution, Article II, Section 43', '2026-05-14', 'static', 'statute_citation', 'Federal and State candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('652f5b8e50a53bb0', 'WA', '["state"]', 'ballot_access', 'What is the signature threshold for an Initiative to the People in Washington?', '["How to get an initiative on the WA ballot","Washington citizen initiative signature requirements","Initiative to the People deadline WA"]', 'An Initiative to the People bypasses the legislature and goes directly to the voters on the general election ballot. Proponents must gather valid signatures from registered voters equal to 8% of the total votes cast for Governor in the last gubernatorial election. Signatures must be submitted to the Secretary of State by early July.', 'https://www.sos.wa.gov/elections/initiatives', 'Washington Secretary of State - Initiatives', '2026-05-14', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('ad33cb3c415ba22d', 'WA', '["state"]', 'ballot_access', 'What is the process for an Initiative to the Legislature in Washington?', '["How does an Initiative to the Legislature work in WA?","Washington indirect initiative process","December initiative deadline WA"]', 'An Initiative to the Legislature requires the same signature threshold (8% of the last gubernatorial vote) but signatures are due in late December. The measure is presented to the legislature in January. The legislature can adopt it into law as is, reject or ignore it (which sends it to the November ballot), or propose an alternative version (which sends both the original and the alternative to the November ballot).', 'https://www.sos.wa.gov/elections/initiatives', 'Washington Secretary of State - Initiatives', '2026-05-14', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('77d7161c080b56cf', 'WA', '["state"]', 'ballot_access', 'What is the signature threshold and timeline for a veto referendum in Washington?', '["How to refer a WA bill to the ballot","Washington citizen referendum rules","Veto referendum deadline Washington state"]', 'Citizens can use a referendum to demand a popular vote on a law recently passed by the legislature. Proponents must gather signatures equal to 4% of the total votes cast for Governor in the last election. The signatures must be filed within 90 days after the final adjournment of the legislative session in which the bill was passed.', 'https://www.sos.wa.gov/elections/initiatives', 'Washington Secretary of State - Referenda', '2026-05-14', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('2f26118bec84de5e', 'WA', '["state","county","municipal"]', 'ballot_access', 'How does the legislature refer a measure to the voters in Washington?', '["Referendum bill by WA legislature","Can the Washington legislature put a law on the ballot?","Legislative referral process WA"]', 'The Washington State Legislature can refer a proposed law to the voters (a Referendum Bill) or propose an amendment to the state constitution. Referendum bills require a simple majority vote in both the House and Senate to be placed on the ballot, whereas constitutional amendments require a two-thirds supermajority vote in both chambers before facing the voters.', 'https://leg.wa.gov/CodeReviser/Pages/WAConstitution.aspx', 'Washington Constitution, Article II and Article XXIII', '2026-05-14', 'static', 'statute_citation', 'Legislators and Strategists', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('2424477c6e417d38', 'WA', '["state"]', 'ballot_access', 'Does Washington require a supermajority voter approval to pass an initiative?', '["Washington initiative pass threshold","Does a ballot measure need 55% in WA?","Vote percentage to pass a law in Washington"]', 'No. Unlike some states that require a 55% or 60% supermajority, in Washington, all citizen initiatives and referenda—whether creating a statute or amending the constitution—require only a simple majority (50% plus one vote) of the votes cast on that specific measure to pass.', 'https://www.sos.wa.gov/elections/initiatives', 'Washington Secretary of State - Initiative FAQ', '2026-05-14', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('5885947d2cfd99e7', 'WA', '["state"]', 'finance_ethics', 'Does Washington still hold advisory votes on tax increases?', '["Washington tax advisory votes 2026","Are advisory votes required in WA?","SB 5082 advisory votes repeal"]', 'No. Historically, Washington required non-binding advisory votes on the ballot whenever the legislature raised taxes (stemming from Initiative 960). However, the legislature passed SB 5082 in 2023, which officially abolished the advisory vote requirement. They will no longer appear on Washington ballots.', 'https://app.leg.wa.gov/billsummary?BillNumber=5082&Year=2023', 'Washington State Legislature - SB 5082 (2023)', '2026-05-14', 'static', 'statute_citation', 'Campaign strategists', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('f61c6ae6b58157d9', 'WA', '["state"]', 'finance_ethics', 'Does the Washington legislature require a two-thirds supermajority to raise taxes?', '["Washington tax increase voting rules","Is the 2/3 tax rule still active in WA?","Initiative 1053 status"]', 'No. While voters repeatedly passed initiatives (such as I-1053) requiring a two-thirds legislative supermajority to raise taxes, the Washington Supreme Court struck down this requirement in 2013 (League of Education Voters v. State). The Court ruled that altering the simple-majority requirement for passing bills requires a constitutional amendment, not a statutory initiative. Tax increases currently require a simple majority.', 'https://casetext.com/case/league-of-educ-voters-v-state-3', 'League of Education Voters v. State (2013)', '2026-05-14', 'static', 'secondary_source', 'Legislators and Strategists', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('d9ddd6ecbaf697ea', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Washington?', '["How close can I campaign to a drop box in WA?","Buffer zone around voting centers Washington","RCW 29A.84.510 electioneering rules"]', 'Under RCW 29A.84.510, it is a gross misdemeanor to electioneer, distribute campaign materials, or solicit votes within 100 feet of an entrance to a voting center or student engagement hub, and within 25 feet of a standalone ballot drop box.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=29A.84.510', 'RCW 29A.84.510', '2026-05-14', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('3df1587efb342535', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Washington''s mail ballot system?', '["What is a provisional ballot in WA?","Voting in person with a lost ballot Washington","When do election workers issue provisional ballots?"]', 'Because Washington is a universal mail-voting state, provisional ballots are less common but are still issued at in-person voting centers. They are used if a voter''s registration cannot be immediately verified, if they are challenged by an election worker, or if they need to cast a ballot but the system shows a mail ballot was already returned in their name. They are counted during canvassing once eligibility is confirmed.', 'https://www.sos.wa.gov/elections/voters/voter-registration/voting-person', 'Washington Secretary of State - Voting in Person', '2026-05-14', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('72c4f01ca8f2ea24', 'WA', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Washington maintain its voter registration lists?', '["WA voter list maintenance rules","How are inactive voters handled in Washington?","ERIC system Washington state"]', 'Washington conducts active list maintenance using the National Change of Address (NCOA) program, Department of Licensing matching, and vital statistics (death records) per RCW 29A.08.610. Washington is also a founding member of ERIC (Electronic Registration Information Center), which compares voter lists across multiple states to identify voters who have moved or died.', 'https://www.sos.wa.gov/elections/data-research/voter-registration-data/voter-list-maintenance', 'Washington Secretary of State - Voter List Maintenance', '2026-05-14', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('0cbfbbe9755a2343', 'WA', '["federal","state","county","municipal"]', 'filing_requirements', 'Can a candidate file via petition instead of paying a filing fee in Washington?', '["Washington filing fee waiver petition","How many signatures to waive filing fee WA?","RCW 29A.24.091 signature equivalent"]', 'Yes. A candidate lacking sufficient funds can file a nominating petition in lieu of a filing fee under RCW 29A.24.091. The requirement is a direct 1-to-1 ratio: the candidate must submit one valid signature of a registered voter in the relevant district for each $1.00 of the required filing fee.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=29A.24.091', 'RCW 29A.24.091', '2026-05-14', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('c225d1e12b593c72', 'WA', '["federal","state","county"]', 'ballot_access', 'How do minor party or independent candidates qualify for the general election under Washington''s Top-2 system?', '["Independent candidate general election access WA","Minor party rules Washington primary","Do third parties have a separate ballot in Washington?"]', 'There is no separate ballot access path for minor party or independent candidates in Washington. Under the Top-2 system, all candidates—regardless of whether they prefer a major party, a minor party, or no party—run on the same primary ballot. To reach the general election, an independent or minor party candidate must finish as one of the top two vote-getters in the primary.', 'https://www.sos.wa.gov/elections/voters/top-2-primary-answers-frequently-asked-questions', 'Washington Secretary of State - Top-2 Primary FAQ', '2026-05-14', 'static', 'official_source_direct', 'Minor party and Independent candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('8a4953fcd141ee04', 'WA', '["federal","state","county","municipal"]', 'filing_requirements', 'How is the candidate filing fee calculated in Washington?', '["Cost to run for office in Washington","WA filing fee for State Senate","1 percent filing fee rule Washington"]', 'For most offices with a fixed annual salary, the filing fee is exactly 1% of the office''s annual salary at the time of filing. For offices without a fixed salary, or where the salary is less than $1,000, the fee is either $10 or $20, depending on the specific office level, per RCW 29A.24.091.', 'https://www.sos.wa.gov/elections/candidates/filing-resources/candidate-filing-faq', 'Washington Secretary of State - Candidate Filing FAQ', '2026-05-14', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('b3b470c9d381149a', 'WA', '["federal","state","county"]', 'ballot_access', 'Does Washington have a sore loser law?', '["Can I run as an independent if I lose the WA primary?","Washington sore loser statute","General election ballot access after primary defeat WA"]', 'Operationally, Washington does not need a traditional sore loser law because of the Top-2 primary. If a candidate runs in the primary and does not finish in the top two, they cannot simply re-file to appear on the general election ballot as an independent, because the general election ballot is strictly limited to the primary''s top two finishers. Their only recourse is to mount a write-in campaign.', 'https://www.sos.wa.gov/elections/voters/top-2-primary-answers-frequently-asked-questions', 'Washington Secretary of State - Top-2 Primary FAQ', '2026-05-14', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('e29887399db16659', 'WA', '["federal"]', 'election_dates', 'Does Washington use the Top-2 system for the Presidential Primary?', '["Washington presidential primary rules","Do I have to pick a party for the WA presidential primary?","Partisan primary Washington president"]', 'No. The Presidential Primary in Washington is entirely separate from the state Top-2 primary. Held in March of presidential election years, it is a partisan process. Voters must sign a declaration on the ballot envelope swearing affiliation to either the Democratic or Republican party in order for their vote to be counted and allocated to delegates.', 'https://www.sos.wa.gov/elections/voters/presidential-primary-faqs', 'Washington Secretary of State - Presidential Primary FAQ', '2026-05-14', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('f8f961a904d39840', 'WA', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements and duties for the Lieutenant Governor of Washington?', '["Role of the Washington Lt. Governor","Qualifications to run for Lt. Governor WA","Does the Lt Gov preside over the WA Senate?"]', 'To run for Lieutenant Governor, a candidate must simply be a qualified elector (US citizen, 18+, WA resident) under Article III, Section 25. The Lieutenant Governor serves as the President of the Washington State Senate, casting tie-breaking votes, and serves as acting Governor when the Governor leaves the state or is incapacitated.', 'https://ltgov.wa.gov/about-the-office/', 'Washington State Lieutenant Governor''s Office', '2026-05-14', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('d8f080cccd0bde12', 'WA', '["state"]', 'candidate_eligibility', 'Does the Washington Attorney General have to be a licensed attorney?', '["Qualifications to run for Attorney General in WA","Do I need to be a member of the bar to be WA AG?","Legal requirements for Washington Attorney General"]', 'While the Washington Constitution (Article III, Sec 25) only explicitly requires statewide executives to be qualified electors, RCW 43.10 outlines the AG''s duties as the state''s chief legal adviser. Practically and historically, candidates must be licensed to practice law in Washington, as the State Supreme Court has ruled that prosecuting attorneys must be admitted to the bar to fulfill their statutory duties.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=43.10', 'RCW 43.10', '2026-05-14', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('6316208ef52b3af6', 'WA', '["judicial"]', 'election_dates', 'How are Washington Supreme Court and Court of Appeals judges selected?', '["Are judges elected in Washington state?","WA Supreme Court terms and elections","Partisan vs nonpartisan judicial races WA"]', 'Justices of the Washington Supreme Court and judges of the Court of Appeals are elected by the voters in nonpartisan elections. Supreme Court Justices (9 members) and Court of Appeals judges both serve six-year terms. If a midterm vacancy occurs, the Governor appoints a replacement who must then stand for election at the next general election.', 'https://www.courts.wa.gov/appellate_trial_courts/', 'Washington State Courts', '2026-05-14', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('741ec2497b750c04', 'WA', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements for Washington State Treasurer and Auditor?', '["Requirements to run for WA Treasurer","Eligibility for Washington State Auditor","Financial background needed for WA Auditor?"]', 'Under Article III, Section 25 of the Washington Constitution, candidates for Treasurer and Auditor face the same minimal requirements as the Governor: they must be a citizen of the United States and a qualified elector (registered voter) of the state. There are no constitutional requirements for specific financial degrees or CPA certifications.', 'https://leg.wa.gov/CodeReviser/Pages/WAConstitution.aspx', 'Washington Constitution, Article III, Section 25', '2026-05-14', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('102e42dffebc8384', 'WA', '["county"]', 'election_dates', 'What are the terms and election cycles for county offices in Washington?', '["When are county sheriffs elected in WA?","Washington county official term lengths","Are county prosecutors on the 2026 ballot?"]', 'Most elected county officials in Washington—including Sheriffs, Prosecuting Attorneys, Auditors, Assessors, Treasurers, and Clerks—serve four-year terms. The vast majority of these 39 county offices are elected during the midterm election cycle, meaning they will be heavily featured on the 2026 ballot.', 'https://www.sos.wa.gov/elections/candidates', 'Washington Secretary of State', '2026-05-14', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('8c0a0764e6532aa7', 'WA', '["state","county","municipal"]', 'election_dates', 'When are special elections held and certified in Washington?', '["Washington special election dates 2026","Canvassing timeline Washington elections","When are WA election results official?"]', 'By statute (RCW 29A.04.321), special elections may only be called in February, April, August (primary date), or November (general election date). Under Washington''s mail voting system, election results take weeks to finalize; counties have 21 days to certify primary and general election results, meaning final winners may not be known until late November.', 'https://www.sos.wa.gov/elections/candidates/election-calendar', 'Washington Secretary of State - Election Calendar', '2026-05-14', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-58-02_washington_full_v1'),
  ('443f5f4785cf0c1c', 'WA', '["state","county","municipal"]', 'recall_rules', 'Does a court review Washington recall petitions before signatures are gathered?', '["Washington recall court sufficiency hearing","Are federal officers subject to WA recall?","How to start a recall against a Washington mayor"]', 'Yes. Washington has a unique ''sufficiency review'' process. Before proponents can gather a single signature, a Superior Court judge must review the recall charges to determine if they meet the legal threshold of misfeasance, malfeasance, or violating the oath of office (RCW 29A.56.140). Note: Members of the U.S. Congress representing Washington cannot be recalled, as federal courts have ruled state recall laws cannot apply to federal officers.', 'https://app.leg.wa.gov/rcw/default.aspx?cite=29A.56.140', 'RCW 29A.56.140', '2026-05-14', 'static', 'statute_citation', 'All candidates and campaigns', 'batch_2026-05-14T20-58-02_washington_full_v1')
